using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9: ZipArchiveEntry now respects the UTF-8 flag, encoding
        // names as UTF-8 by default. The legacy Java consumer expects
        // Shift-JIS, so specify the encoding explicitly to suppress the
        // UTF-8 flag and write entry names in Shift-JIS.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var stream = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(stream, ZipArchiveMode.Create,
            leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("гѓ¬гѓќгѓјгѓ€/жњ€ж¬Ў.csv");  // Japanese path
        archive.CreateEntry("donnГ©es/rГ©sumГ©.txt"); // French accented
    }
}

